#include <bits/stdc++.h>
using namespace std;

struct Vec3{double x=0,y=0,z=0;};
static inline Vec3 operator+(const Vec3&a,const Vec3&b){return {a.x+b.x,a.y+b.y,a.z+b.z};}
static inline Vec3 operator-(const Vec3&a,const Vec3&b){return {a.x-b.x,a.y-b.y,a.z-b.z};}
static inline Vec3 operator*(const Vec3&a,double s){return {a.x*s,a.y*s,a.z*s};}
static inline Vec3 operator/(const Vec3&a,double s){return {a.x/s,a.y/s,a.z/s};}
static inline double dot3(const Vec3&a,const Vec3&b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static inline Vec3 cross3(const Vec3&a,const Vec3&b){return {a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}
static inline double norm2(const Vec3&a){return dot3(a,a);} static inline double norm3(const Vec3&a){return sqrt(max(0.0,norm2(a)));}
struct Face{int v[3];};
struct Mesh{vector<Vec3> V; vector<Face> F;};

static int N0,M0; static Mesh ORIG; static Vec3 BBmin,BBmax; static double DIAG=1,TAU=1,TAU2=1; static chrono::steady_clock::time_point T0;
static inline double elapsed(){return chrono::duration<double>(chrono::steady_clock::now()-T0).count();}
struct FastInput{vector<char> b; char*p=nullptr; FastInput(){char t[1<<16]; size_t n; b.reserve(1<<26); while((n=fread(t,1,sizeof(t),stdin))>0)b.insert(b.end(),t,t+n); b.push_back(0); p=b.data();} void skip(){while(*p==' '||*p=='\n'||*p=='\r'||*p=='\t')++p;} int nextInt(){skip(); int s=1; if(*p=='-'){s=-1;++p;} int x=0; while(*p>='0'&&*p<='9'){x=x*10+*p-'0';++p;} return x*s;} double nextDouble(){skip(); char*e; double x=strtod(p,&e); p=e; return x;} char nextChar(){skip(); return *p?*p++:0;}};
static inline uint64_t edgeKey(int a,int b){if(a>b)swap(a,b); return (uint64_t)(uint32_t)a<<32 | (uint32_t)b;}
static inline array<int,3> faceKey(int a,int b,int c){array<int,3>s={a,b,c}; sort(s.begin(),s.end()); return s;}
static bool sameFace(const Face&f,int a,int b,int c){return faceKey(f.v[0],f.v[1],f.v[2])==faceKey(a,b,c);}

static bool readMesh(){FastInput in; N0=in.nextInt(); M0=in.nextInt(); if(N0<=0||M0<=0)return false; ORIG.V.resize(N0); ORIG.F.resize(M0); BBmin={1e100,1e100,1e100}; BBmax={-1e100,-1e100,-1e100}; for(int i=0;i<N0;i++){char c=in.nextChar(); if(c!='v'&&c!='V')--in.p; Vec3 p{in.nextDouble(),in.nextDouble(),in.nextDouble()}; ORIG.V[i]=p; BBmin.x=min(BBmin.x,p.x); BBmin.y=min(BBmin.y,p.y); BBmin.z=min(BBmin.z,p.z); BBmax.x=max(BBmax.x,p.x); BBmax.y=max(BBmax.y,p.y); BBmax.z=max(BBmax.z,p.z);} for(int i=0;i<M0;i++){char c=in.nextChar(); if(c!='f'&&c!='F')--in.p; int a=in.nextInt()-1,b=in.nextInt()-1,c2=in.nextInt()-1; ORIG.F[i]={{a,b,c2}};} DIAG=norm3(BBmax-BBmin); if(!(DIAG>0))DIAG=1; TAU=0.05*DIAG*0.997; TAU2=TAU*TAU; return true;}
static double signedVolume6(const Mesh&m){long double s=0; for(auto &f:m.F){auto&a=m.V[f.v[0]]; auto&b=m.V[f.v[1]]; auto&c=m.V[f.v[2]]; s+=(long double)dot3(a,cross3(b,c));} return (double)s;}
static void matchOrientation(Mesh&m){if(signedVolume6(ORIG)*signedVolume6(m)<0)for(auto&f:m.F)swap(f.v[1],f.v[2]);}
static bool strongValidator(const Mesh&m){int n=m.V.size(), mf=m.F.size(); if(n<=0||mf<=0||n>N0)return false; vector<unsigned char>used(n,0); vector<uint64_t>edges; edges.reserve((size_t)mf*3); vector<array<int,3>>fs; fs.reserve(mf); double amin=max(1e-30,1e-24*DIAG*DIAG); for(auto&f:m.F){int a=f.v[0],b=f.v[1],c=f.v[2]; if(a<0||b<0||c<0||a>=n||b>=n||c>=n||a==b||a==c||b==c)return false; Vec3 cr=cross3(m.V[b]-m.V[a],m.V[c]-m.V[a]); if(norm2(cr)<=amin)return false; used[a]=used[b]=used[c]=1; edges.push_back(edgeKey(a,b)); edges.push_back(edgeKey(b,c)); edges.push_back(edgeKey(c,a)); fs.push_back(faceKey(a,b,c));} for(int i=0;i<n;i++)if(!used[i])return false; sort(fs.begin(),fs.end()); if(adjacent_find(fs.begin(),fs.end())!=fs.end())return false; sort(edges.begin(),edges.end()); for(size_t i=0;i<edges.size();){size_t j=i+1; while(j<edges.size()&&edges[j]==edges[i])++j; if(j-i!=2)return false; i=j;} return true;}
static void outputMesh(const Mesh&m){printf("%d %d\n",(int)m.V.size(),(int)m.F.size()); for(auto&p:m.V)printf("v %.15g %.15g %.15g\n",p.x,p.y,p.z); for(auto&f:m.F)printf("f %d %d %d\n",f.v[0]+1,f.v[1]+1,f.v[2]+1);}

struct Hash{double cell=1; const vector<Vec3>*P=nullptr; unordered_map<unsigned long long,vector<int>>mp; long long fl(double x)const{return (long long)floor(x/cell);} static unsigned long long mix(long long x,long long y,long long z){const long long O=1LL<<20; unsigned long long a=x+O,b=y+O,c=z+O; return a*11995408973635179863ull ^ b*10150724397891781847ull ^ c*1609587929392839161ull;} void build(const vector<Vec3>&v,double r){P=&v; cell=max(r,1e-12); mp.clear(); mp.reserve(v.size()*2+7); for(int i=0;i<(int)v.size();++i){auto&p=v[i]; mp[mix(fl(p.x),fl(p.y),fl(p.z))].push_back(i);}} bool near(const Vec3&p,double r2)const{long long ix=fl(p.x),iy=fl(p.y),iz=fl(p.z); for(long long dx=-1;dx<=1;dx++)for(long long dy=-1;dy<=1;dy++)for(long long dz=-1;dz<=1;dz++){auto it=mp.find(mix(ix+dx,iy+dy,iz+dz)); if(it==mp.end())continue; for(int id:it->second)if(norm2((*P)[id]-p)<=r2)return true;} return false;}};
static void addTet(Mesh&m,const Vec3&p){double e=max(1e-8,DIAG*4e-6); int s=m.V.size(); m.V.push_back(p); m.V.push_back({p.x+e,p.y,p.z}); m.V.push_back({p.x,p.y+e,p.z}); m.V.push_back({p.x,p.y,p.z+e}); m.F.push_back({{s,s+2,s+1}}); m.F.push_back({{s,s+1,s+3}}); m.F.push_back({{s,s+3,s+2}}); m.F.push_back({{s+1,s+2,s+3}});}
static bool repairHausdorff(Mesh&m,bool tets=true){if(m.V.empty()||m.F.empty()||m.V.size()>ORIG.V.size())return false; Hash oh; oh.build(ORIG.V,TAU); for(auto&p:m.V)if(!oh.near(p,TAU2))return false; Hash ch; ch.build(m.V,TAU); if(tets){for(auto&p:ORIG.V)if(!ch.near(p,TAU2)){if((int)m.V.size()+4>N0)return false; addTet(m,p); ch.build(m.V,TAU);}} for(auto&p:ORIG.V)if(!ch.near(p,TAU2))return false; return (int)m.V.size()<=N0&&strongValidator(m);}

static bool detectLatLong(int&rings,int&sides){if(N0<10||M0!=2*(N0-2))return false; for(int v=8;v<=4096;v++){if((N0-2)%v)continue; int r=(N0-2)/v; if(r<3)continue; bool ok=true; int step=max(1,v/64); for(int j=0;j<v&&ok;j+=step){int a=1+j,b=1+(j+1)%v; if(!sameFace(ORIG.F[j],0,b,a))ok=false;} int span=max(1,(r-1)*v/180); for(int q=0;q<(r-1)*v&&ok;q+=span){int rr=q/v,j=q-rr*v; int a=1+rr*v+j,b=1+rr*v+(j+1)%v,c=1+(rr+1)*v+j,d=1+(rr+1)*v+(j+1)%v; int fid=v+2*q; if(fid+1>=M0||!sameFace(ORIG.F[fid],a,b,c)||!sameFace(ORIG.F[fid+1],b,d,c))ok=false;} int bot=v+2*(r-1)*v; for(int j=0;j<v&&ok;j+=step){int c=1+(r-1)*v+j,d=1+(r-1)*v+(j+1)%v; if(bot+j>=M0||!sameFace(ORIG.F[bot+j],N0-1,c,d))ok=false;} if(ok){rings=r;sides=v;return true;}} return false;}
static Mesh buildLatLong(int rings,int sides,int R,int S){Mesh m; if(R<2||S<8)return m; m.V.push_back(ORIG.V[0]); vector<int>rr(R),ss(S); for(int i=0;i<R;i++)rr[i]=max(1,min(rings,1+(int)llround((double)i*(rings-1)/max(1,R-1)))); for(int j=0;j<S;j++)ss[j]=max(0,min(sides-1,(int)((long long)j*sides/S))); for(int i=0;i<R;i++)for(int j=0;j<S;j++)m.V.push_back(ORIG.V[1+(rr[i]-1)*sides+ss[j]]); int bot=m.V.size(); m.V.push_back(ORIG.V[N0-1]); auto id=[&](int i,int j){return 1+i*S+((j%S+S)%S);}; auto add=[&](int a,int b,int c){m.F.push_back({{a,b,c}});}; for(int j=0;j<S;j++)add(0,id(0,j+1),id(0,j)); for(int i=0;i+1<R;i++)for(int j=0;j<S;j++){int a=id(i,j),b=id(i,j+1),c=id(i+1,j),d=id(i+1,j+1);add(a,b,c);add(b,d,c);} for(int j=0;j<S;j++)add(bot,id(R-1,j),id(R-1,j+1)); matchOrientation(m); return m;}
static bool tryLatLong(Mesh&best){int r=0,s=0; if(!detectLatLong(r,s))return false; vector<pair<int,int>>tr; for(double q:{18.0,14.0,10.0,8.0,6.0,4.5,3.5,2.5,2.0,1.5})tr.push_back({max(2,(int)ceil(r/q)),max(8,(int)ceil(s/q))}); sort(tr.begin(),tr.end(),[](auto&a,auto&b){return a.first*a.second<b.first*b.second;}); for(auto [R,S]:tr){Mesh m=buildLatLong(r,s,R,S); if(m.V.size()<best.V.size()&&repairHausdorff(m,true)){best=move(m);return true;}} return false;}
static bool detectTorus(int&U,int&V){if(N0<36||M0!=2*N0)return false; for(int vv=6;vv<=2048;vv++){if(N0%vv)continue; int uu=N0/vv; if(uu<6)continue; bool ok=true; int step=max(1,N0/700),chk=0; for(int q=0;q<N0&&chk<700&&ok;q+=step,++chk){int i=q/vv,j=q-i*vv,ni=(i+1==uu?0:i+1),nj=(j+1==vv?0:j+1); int a=i*vv+j,b=i*vv+nj,c=ni*vv+j,d=ni*vv+nj,f0=2*q,f1=f0+1; if(f1>=M0){ok=false;break;} bool m0=sameFace(ORIG.F[f0],a,b,c)||sameFace(ORIG.F[f0],b,d,c)||sameFace(ORIG.F[f0],a,c,d)||sameFace(ORIG.F[f0],a,b,d); bool m1=sameFace(ORIG.F[f1],a,b,c)||sameFace(ORIG.F[f1],b,d,c)||sameFace(ORIG.F[f1],a,c,d)||sameFace(ORIG.F[f1],a,b,d); if(!(m0&&m1))ok=false;} if(ok){U=uu;V=vv;return true;}} return false;}
static Mesh buildTorus(int U,int V,int U2,int V2){Mesh m; if(U2<3||V2<3)return m; for(int i=0;i<U2;i++){int oi=(int)((long long)i*U/U2); for(int j=0;j<V2;j++){int oj=(int)((long long)j*V/V2); m.V.push_back(ORIG.V[oi*V+oj]);}} auto id=[&](int i,int j){i=(i%U2+U2)%U2; j=(j%V2+V2)%V2; return i*V2+j;}; auto add=[&](int a,int b,int c){m.F.push_back({{a,b,c}});}; for(int i=0;i<U2;i++)for(int j=0;j<V2;j++){int a=id(i,j),b=id(i,j+1),c=id(i+1,j),d=id(i+1,j+1);add(a,b,c);add(b,d,c);} matchOrientation(m); return m;}
static bool tryTorus(Mesh&best){int U=0,V=0; if(!detectTorus(U,V))return false; vector<pair<int,int>>tr; for(double q:{18.0,14.0,10.0,8.0,6.0,4.5,3.5,2.5,2.0,1.5})tr.push_back({max(6,(int)ceil(U/q)),max(6,(int)ceil(V/q))}); sort(tr.begin(),tr.end(),[](auto&a,auto&b){return a.first*a.second<b.first*b.second;}); for(auto [u,v]:tr){Mesh m=buildTorus(U,V,u,v); if(m.V.size()<best.V.size()&&repairHausdorff(m,true)){best=move(m);return true;}} return false;}

static bool tryBox(Mesh&best){Vec3 ext=BBmax-BBmin; if(min(ext.x,min(ext.y,ext.z))<=1e-12)return false; double sampleMax=0; int stride=max(1,N0/200000); for(int i=0;i<N0;i+=stride){auto&p=ORIG.V[i]; double dx=min(fabs(p.x-BBmin.x),fabs(p.x-BBmax.x)); double dy=min(fabs(p.y-BBmin.y),fabs(p.y-BBmax.y)); double dz=min(fabs(p.z-BBmin.z),fabs(p.z-BBmax.z)); sampleMax=max(sampleMax,min(dx,min(dy,dz)));} if(sampleMax>TAU*0.45)return false; for(int S: {6,8,10,12,16,20,24,32,40,48}){if((S+1)*(S+1)*6>N0)continue; Mesh m; map<tuple<int,int,int>,int> idmap; auto get=[&](int i,int j,int k){auto key=make_tuple(i,j,k); auto it=idmap.find(key); if(it!=idmap.end())return it->second; Vec3 p{BBmin.x+ext.x*i/S,BBmin.y+ext.y*j/S,BBmin.z+ext.z*k/S}; int id=m.V.size(); idmap[key]=id; m.V.push_back(p); return id;}; auto add=[&](int a,int b,int c){m.F.push_back({{a,b,c}});}; for(int i=0;i<S;i++)for(int j=0;j<S;j++){int a=get(i,j,0),b=get(i+1,j,0),c=get(i+1,j+1,0),d=get(i,j+1,0); add(a,c,b); add(a,d,c); a=get(i,j,S);b=get(i+1,j,S);c=get(i+1,j+1,S);d=get(i,j+1,S); add(a,b,c); add(a,c,d);} for(int j=0;j<S;j++)for(int k=0;k<S;k++){int a=get(0,j,k),b=get(0,j+1,k),c=get(0,j+1,k+1),d=get(0,j,k+1); add(a,c,b); add(a,d,c); a=get(S,j,k);b=get(S,j+1,k);c=get(S,j+1,k+1);d=get(S,j,k+1); add(a,b,c); add(a,c,d);} for(int i=0;i<S;i++)for(int k=0;k<S;k++){int a=get(i,0,k),b=get(i+1,0,k),c=get(i+1,0,k+1),d=get(i,0,k+1); add(a,b,c); add(a,c,d); a=get(i,S,k);b=get(i+1,S,k);c=get(i+1,S,k+1);d=get(i,S,k+1); add(a,c,b); add(a,d,c);} matchOrientation(m); if(m.V.size()<best.V.size()&&repairHausdorff(m,true)){best=move(m);return true;}} return false;}

struct Simp{int n,m,activeV,activeF; vector<Vec3>P; vector<Face>F; vector<vector<int>>inc; vector<unsigned char>av,af; vector<double>rad; vector<int>A,B; int st=1; Simp(const Mesh&s){n=s.V.size();m=s.F.size();P=s.V;F=s.F;av.assign(n,1);af.assign(m,1);rad.assign(n,0);inc.assign(n,{}); vector<int>d(n,0); for(auto&f:F){d[f.v[0]]++;d[f.v[1]]++;d[f.v[2]]++;} for(int i=0;i<n;i++)inc[i].reserve(d[i]+8); for(int i=0;i<m;i++){inc[F[i].v[0]].push_back(i);inc[F[i].v[1]].push_back(i);inc[F[i].v[2]].push_back(i);} activeV=n;activeF=m;A.assign(n,0);B.assign(n,0);} bool has(int id,int v){auto&f=F[id];return f.v[0]==v||f.v[1]==v||f.v[2]==v;} int third(int id,int u,int v){auto&f=F[id];for(int k=0;k<3;k++){int x=f.v[k];if(x!=u&&x!=v)return x;}return -1;} bool ef(int u,int v,int E[2],int O[2]){int c=0; for(int id:inc[u])if(af[id]&&has(id,v)){if(c>=2)return false;E[c]=id;O[c]=third(id,u,v);c++;}return c==2&&O[0]!=O[1]&&O[0]>=0&&O[1]>=0;} bool link(int u,int v,int o0,int o1){if(++st>1000000000){fill(A.begin(),A.end(),0);fill(B.begin(),B.end(),0);st=1;} for(int id:inc[u])if(af[id]&&has(id,u)){for(int k=0;k<3;k++){int x=F[id].v[k]; if(x!=u&&x!=v)A[x]=st;}} int c=0,g0=0,g1=0; for(int id:inc[v])if(af[id]&&has(id,v)){for(int k=0;k<3;k++){int x=F[id].v[k]; if(x==u||x==v)continue; if(A[x]==st&&B[x]!=st){B[x]=st;c++; if(x==o0)g0=1; if(x==o1)g1=1; if(c>2)return false;}}} return c==2&&g0&&g1;} bool dup(int keep,int rem,int e0,int e1,int a,int b,int c){auto key=faceKey(a,b,c); vector<int>ids=inc[keep]; ids.insert(ids.end(),inc[rem].begin(),inc[rem].end()); sort(ids.begin(),ids.end()); ids.erase(unique(ids.begin(),ids.end()),ids.end()); for(int id:ids)if(af[id]&&id!=e0&&id!=e1){Face g=F[id]; for(int k=0;k<3;k++)if(g.v[k]==rem)g.v[k]=keep; if(g.v[0]==g.v[1]||g.v[0]==g.v[2]||g.v[1]==g.v[2])continue; if(faceKey(g.v[0],g.v[1],g.v[2])==key)return true;}return false;} bool eval(int keep,int rem,int e0,int e1,double md,double afrac,double pt){double nr=max(rad[keep],rad[rem]+norm3(P[rem]-P[keep])); if(nr>TAU*.996)return false; vector<int>ids=inc[rem]; ids.insert(ids.end(),inc[keep].begin(),inc[keep].end()); sort(ids.begin(),ids.end()); ids.erase(unique(ids.begin(),ids.end()),ids.end()); for(int id:ids)if(af[id]&&id!=e0&&id!=e1){Face old=F[id],nw=old; for(int k=0;k<3;k++)if(nw.v[k]==rem)nw.v[k]=keep; if(nw.v[0]==nw.v[1]||nw.v[0]==nw.v[2]||nw.v[1]==nw.v[2])return false; Vec3 co=cross3(P[old.v[1]]-P[old.v[0]],P[old.v[2]]-P[old.v[0]]), cn=cross3(P[nw.v[1]]-P[nw.v[0]],P[nw.v[2]]-P[nw.v[0]]); double ao=norm3(co), an=norm3(cn); if(!(ao>1e-22*DIAG*DIAG)||!(an>1e-22*DIAG*DIAG))return false; double d=dot3(co,cn)/(ao*an); if(d<md||an<ao*afrac)return false; if(fabs(dot3(co/ao,P[keep]-P[old.v[0]]))>pt)return false; if(has(id,rem)&&dup(keep,rem,e0,e1,nw.v[0],nw.v[1],nw.v[2]))return false;} return true;} void apply(int keep,int rem,int e0,int e1){if(af[e0]){af[e0]=0;activeF--;} if(af[e1]){af[e1]=0;activeF--;} for(int id:inc[rem])if(af[id]&&has(id,rem)){for(int k=0;k<3;k++)if(F[id].v[k]==rem)F[id].v[k]=keep; if(F[id].v[0]==F[id].v[1]||F[id].v[0]==F[id].v[2]||F[id].v[1]==F[id].v[2]){af[id]=0;activeF--;} else inc[keep].push_back(id);} rad[keep]=max(rad[keep],rad[rem]+norm3(P[rem]-P[keep])); av[rem]=0;activeV--; vector<int>w; for(int id:inc[keep])if(af[id]&&has(id,keep))w.push_back(id); sort(w.begin(),w.end());w.erase(unique(w.begin(),w.end()),w.end()); inc[keep].swap(w); vector<int>().swap(inc[rem]);} bool collapse(int u,int v,double md,double ar,double pt){if(u==v||!av[u]||!av[v])return false; int E[2],O[2]; if(!ef(u,v,E,O)||!link(u,v,O[0],O[1]))return false; bool uv=eval(u,v,E[0],E[1],md,ar,pt), vu=eval(v,u,E[0],E[1],md,ar,pt); if(!uv&&!vu)return false; if(vu&&!uv)apply(v,u,E[0],E[1]); else apply(u,v,E[0],E[1]); return true;} vector<pair<double,uint64_t>> edges(double Lmax){unordered_set<uint64_t>seen; vector<pair<double,uint64_t>>e; seen.reserve(m*3); for(int id=0;id<m;id++)if(af[id]){int a[3]={F[id].v[0],F[id].v[1],F[id].v[2]}; for(int k=0;k<3;k++){int u=a[k],v=a[(k+1)%3]; if(!av[u]||!av[v])continue; uint64_t key=edgeKey(u,v); if(seen.insert(key).second){double L=norm3(P[u]-P[v]); if(L<=Lmax)e.push_back({L,key});}}} sort(e.begin(),e.end()); return e;} Mesh snap(){Mesh s; vector<int>id(n,-1); for(int i=0;i<n;i++)if(av[i]){id[i]=s.V.size();s.V.push_back(P[i]);} for(int i=0;i<m;i++)if(af[i]){int a=F[i].v[0],b=F[i].v[1],c=F[i].v[2]; if(id[a]>=0&&id[b]>=0&&id[c]>=0&&a!=b&&a!=c&&b!=c)s.F.push_back({{id[a],id[b],id[c]}});} return s;} Mesh run(){struct Ph{double L,md,ar,pt;}; vector<Ph>ph={{TAU*.55,.999,.45,TAU*.08},{TAU*.80,.995,.25,TAU*.16},{TAU*1.10,.985,.12,TAU*.28},{TAU*1.50,.960,.05,TAU*.45},{TAU*1.90,.920,.02,TAU*.70}}; Mesh best; for(auto&p:ph){if(elapsed()>16.0)break; for(int rep=0;rep<2&&elapsed()<16.0;rep++){auto es=edges(p.L); int done=0; for(auto&x:es){if((done&511)==0&&elapsed()>16.6)break; int u=x.second>>32,v=x.second&0xffffffffu; if(collapse(u,v,p.md,p.ar,p.pt))done++;} if(done<8)break;} Mesh s=snap(); if(!s.V.empty()&&(best.V.empty()||s.V.size()<best.V.size()))best=move(s);} return best;}};

int main(){T0=chrono::steady_clock::now(); if(!readMesh())return 0; if(N0<=8){outputMesh(ORIG);return 0;} Mesh best=ORIG; bool have=false; Mesh c=best; if(tryBox(c)&&c.V.size()<best.V.size()){best=move(c);have=true;} c=best; if(tryLatLong(c)&&c.V.size()<best.V.size()){best=move(c);have=true;} c=best; if(tryTorus(c)&&c.V.size()<best.V.size()){best=move(c);have=true;} if(!have&&elapsed()<16.5){Simp s(ORIG); c=s.run(); if(!c.V.empty()&&c.V.size()<best.V.size()&&repairHausdorff(c,false)){best=move(c);have=true;}} if(!have||!strongValidator(best)||best.V.size()>ORIG.V.size())best=ORIG; outputMesh(best); return 0;}